mapper.select:
SELECT t.*, p.name as project_name, u1.real_name as assignee_name, u2.real_name as reporter_name FROM task t LEFT JOIN project p ON t.project_id = p.id LEFT JOIN user u1 ON t.assignee_id = u1.id LEFT JOIN user u2 ON t.reporter_id = u2.id
AND t.project_id = #{projectId}
AND t.name LIKE CONCAT('%', #{name}, '%')
AND t.status = #{status}
AND t.priority = #{priority}
AND t.assignee_id = #{assigneeId}
ORDER BY t.create_time DESC
